'use client'

import Image from 'next/image'
import Link from 'next/link'
import { use, useState } from 'react'
import { usePathname } from 'next/navigation'
import { HiSearch, HiX } from 'react-icons/hi'
import { FaFacebook, FaLinkedin, FaInstagram, FaYoutube } from 'react-icons/fa'

export default function ServicesPage({
  params,
  searchParams,
}: {
  params: Promise<{ locale: string }>
  searchParams: Promise<{ search?: string; notfound?: string }>
}) {
  const { locale } = use(params)
  const { search, notfound } = use(searchParams)
  const isVi = locale === 'vi'
  const pathname = usePathname()
  const pathWithoutLocale = pathname.replace(/^\/(en|vi|de|fr)/, '') || '/'
  const [isSearchOpen, setIsSearchOpen] = useState(false)
  const [searchTerm, setSearchTerm] = useState('')

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault()
    if (!searchTerm.trim()) return

    const query = searchTerm.trim().toLowerCase()
    
    // Service matching logic
    const serviceMatches = [
      { 
        keywords: ['labor', 'labour', 'lao động', 'nhân lực', 'supply', 'cung ứng', 'quản lý'],
        url: `/${locale}/services/labor-supply`
      },
      { 
        keywords: ['cargo', 'loading', 'unloading', 'bốc xếp', 'bốc dỡ', 'hàng hóa'],
        url: `/${locale}/services/cargo-loading`
      },
      { 
        keywords: ['transport', 'inland', 'vận tải', 'vận chuyển', 'nội địa', 'đường bộ', 'road'],
        url: `/${locale}/services/inland-transport`
      },
      { 
        keywords: ['packaging', 'package', 'đóng gói', 'gói hàng', 'máy móc'],
        url: `/${locale}/services/packaging`
      },
      { 
        keywords: ['lifting', 'installation', 'nâng', 'hạ', 'lắp đặt', 'cẩu', 'crane', 'máy'],
        url: `/${locale}/services/lifting-installation`
      },
      { 
        keywords: ['vehicle', 'rental', 'cho thuê', 'phương tiện', 'xe', 'forklift', 'xe nâng'],
        url: `/${locale}/services/vehicle-rental`
      },
    ]

    // Find matching service
    const match = serviceMatches.find(service => 
      service.keywords.some(keyword => 
        query.includes(keyword) || keyword.includes(query)
      )
    )

    if (match) {
      window.location.href = match.url
    } else {
      // No match - go to services page with search query
      window.location.href = `/${locale}/services?search=${encodeURIComponent(searchTerm.trim())}&notfound=true`
    }
  }

  const sidebarMenu = [
    { title: isVi ? 'THƯ NGỎ' : 'OPEN LETTER', href: `/${locale}/open-letter` },
    { title: isVi ? 'DỊCH VỤ' : 'SERVICES', href: `/${locale}/services` },
    { title: isVi ? 'GIẤY PHÉP KINH DOANH' : 'BUSINESS LICENSE', href: `/${locale}/business-license` },
    { title: isVi ? 'TẦM NHÌN & SỨ MỆNH' : 'VISION & MISSION', href: `/${locale}/vision-mission` },
    { title: isVi ? 'TUÂN THỦ' : 'COMPLIANCE', href: `/${locale}/compliance` },
    { title: isVi ? 'ĐỐI TÁC & KHÁCH HÀNG' : 'PARTNERS & CLIENTS', href: `/${locale}/partners` },
    { title: isVi ? 'GIỚI THIỆU' : 'ABOUT US', href: `/${locale}/about` },
    // { title: isVi ? 'LIÊN HỆ' : 'CONTACT', href: `/${locale}/contact` },
  ]

  const services = [
    {
      title: isVi ? 'Cung Ứng và Quản Lý Nguồn Lao Động' : 'Supply and Management of Labor Resources',
      description: isVi
        ? 'Dịch vụ cho thuê lại lao động phổ thông giúp chuyển chi phí lương từ định phí sang biến phí, giảm thiểu rủi ro pháp lý.'
        : 'Unskilled labor subleasing service helps convert salary costs from fixed to variable costs, minimize legal risks.',
      image: '/images/Họp triển khai công việc.jpg',
      link: '/services/labor-supply',
    },
    {
      title: isVi ? 'Bốc Xếp Hàng Hóa' : 'Cargo Loading and Unloading',
      description: isVi
        ? 'Sử dụng sức lao động để bốc xếp, bốc dỡ hàng hóa lên và xuống các phương tiện chuyên chở.'
        : 'Use of labor to load and unload goods onto and off transportation vehicles.',
      image: '/images/Hạ hàng.jpg',
      link: '/services/cargo-loading',
    },
    {
      title: isVi ? 'Vận Tải Nội Địa' : 'Inland Transport',
      description: isVi
        ? 'Vận tải đường bộ, đường thủy và đa phương thức từ Bắc vào Nam với sự an toàn tuyệt đối.'
        : 'Road, waterway and multi-modal transport from North to South with absolute safety.',
      image: '/images/Dịch vụ chuyển máy CNC.jpg',
      link: '/services/inland-transport',
    },
    {
      title: isVi ? 'Đóng Gói Hàng Hóa, Máy Móc' : 'Packaging of Goods and Machinery',
      description: isVi
        ? 'Dịch vụ đóng gói chuyên nghiệp cho máy móc công nghiệp, hàng dễ vỡ, hóa chất và hàng nguy hiểm.'
        : 'Professional packaging services for industrial machinery, fragile goods, chemicals and dangerous goods.',
      image: '/images/Dịch vụ đóng gói máy móc.jpg',
      link: '/services/packaging',
    },
    {
      title: isVi ? 'Nâng Hạ, Lắp Đặt Máy Móc' : 'Lifting and Installation',
      description: isVi
        ? 'Đội ngũ giàu kinh nghiệm với trang thiết bị chuyên dụng phục vụ vận chuyển máy móc công nghiệp nặng.'
        : 'Experienced staff with specialized equipment serving transportation of heavy industrial machinery.',
      image: '/images/Cẩu máy ép nhựa.jpg',
      link: '/services/lifting-installation',
    },
    {
      title: isVi ? 'Cho Thuê Phương Tiện' : 'Vehicle Rental',
      description: isVi
        ? 'Cho thuê các loại xe nâng, xe cẩu đáp ứng nhu cầu xây dựng, lắp đặt và di dời máy móc.'
        : 'Rental of forklifts and cranes for construction, installation and machinery relocation.',
      image: '/images/Rùa điện 30 tấn.jpg',
      link: '/services/vehicle-rental',
    },
  ]

  return (
    <div className="min-h-screen relative">
      {/* Background Image - Full Screen, No Margins */}
      <div 
        className="fixed inset-0 z-0 bg-cover bg-center bg-no-repeat"
        style={{ backgroundImage: `url('${encodeURI("/images/Dịch vụ chuyển máy CNC.jpg")}')` }}
      >
        <div className="absolute inset-0 bg-white/70"></div>
      </div>

      {/* Content with Margins */}
      <div className="relative z-10" style={{ marginLeft: '240px', marginRight: '240px', marginTop: '80px' }}>
        {/* Header */}
        <header className="rounded-xl overflow-hidden shadow-lg">
        {/* Top Blue Bar with Logo */}
        <div className="bg-[#1F5F9E] text-white">
          <div className="container mx-auto px-4 py-4 flex items-center justify-between">
            <Link href={`/${locale}`} className="flex items-center gap-3">
              <div className="bg-white rounded-lg p-2 shadow-md">
                <Image
                  src="/images/logo_horizontal.png"
                  alt="Nhat Minh Huy"
                  width={200}
                  height={50}
                  className="h-12 w-auto"
                  priority
                />
              </div>
            </Link>
            
            {/* Language Switcher */}
            <div className="flex items-center gap-2">
              <Link
                href={`/en${pathWithoutLocale}`}
                className={`px-4 py-2 rounded font-bold text-sm transition-colors ${
                  locale === 'en'
                    ? 'bg-[#FFD900] text-[#1F5F9E]'
                    : 'bg-white/10 text-white hover:bg-white/20'
                }`}
              >
                EN
              </Link>
              <Link
                href={`/vi${pathWithoutLocale}`}
                className={`px-4 py-2 rounded font-bold text-sm transition-colors ${
                  locale === 'vi'
                    ? 'bg-[#FFD900] text-[#1F5F9E]'
                    : 'bg-white/10 text-white hover:bg-white/20'
                }`}
              >
                VI
              </Link>
            </div>
          </div>
        </div>

        {/* Yellow Contact Bar */}
        <div className="bg-[#FFD900]">
          <div className="container mx-auto px-4 py-3 flex items-center justify-between">
            <div className="flex items-center gap-6 text-sm text-[#1F5F9E] font-semibold">
              <a 
                href="tel:+84968903913" 
                className="flex items-center gap-2 hover:underline transition-all"
                title="Call us"
              >
                +84 968 903 913
              </a>
              <span>or</span>
              <button
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  const email = 'nhatminhhuy.co@gmail.com';
                  // Try to open email client
                  window.location.href = `mailto:${email}`;
                  // Also copy to clipboard
                  navigator.clipboard.writeText(email).then(() => {
                    alert(isVi ? 'Email đã được sao chép!' : 'Email copied to clipboard!');
                  }).catch((err) => {
                    console.error('Failed to copy email:', err);
                  });
                }}
                className="hover:underline transition-all cursor-pointer bg-transparent border-none text-[#1F5F9E] font-semibold text-sm"
                title="Send us an email"
                type="button"
              >
                nhatminhhuy.co@gmail.com
              </button>
            </div>
            <nav className="flex items-center gap-8 text-sm font-bold text-[#1F5F9E]">
              <Link href={`/${locale}`} className="hover:underline">
                HOME
              </Link>
              <Link href={`/${locale}/contact`} className="hover:underline">
                CONTACT
              </Link>
              <button 
                onClick={() => setIsSearchOpen(true)}
                className="hover:opacity-70 transition-opacity cursor-pointer bg-transparent border-none p-0"
                aria-label={isVi ? 'Tìm kiếm' : 'Search'}
                type="button"
              >
                <HiSearch className="w-5 h-5" />
              </button>
            </nav>
          </div>
        </div>
      </header>

      {/* Search Modal */}
      {isSearchOpen && (
        <div 
          className="fixed inset-0 z-50 flex items-start justify-center pt-32 px-4"
          onClick={() => setIsSearchOpen(false)}
        >
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm"></div>
          <div 
            className="relative w-full max-w-2xl glass-card p-8 animate-slideDown"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={() => setIsSearchOpen(false)}
              className="absolute top-4 right-4 text-gray-500 hover:text-[#1F5F9E] transition-colors"
              aria-label="Close"
            >
              <HiX className="w-6 h-6" />
            </button>
            <form onSubmit={handleSearch} className="space-y-6">
              <div>
                <h2 className="text-2xl font-bold text-[#1F5F9E] mb-2">
                  {isVi ? 'Tìm kiếm dịch vụ' : 'Search Services'}
                </h2>
                <p className="text-gray-600 text-sm">
                  {isVi ? 'Nhập từ khóa để tìm kiếm dịch vụ của chúng tôi' : 'Enter keywords to search our services'}
                </p>
              </div>
              <div className="relative">
                <HiSearch className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <input
                  type="text"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder={isVi ? 'Ví dụ: vận chuyển, cẩu máy, đóng gói...' : 'e.g., transport, lifting, packaging...'}
                  className="w-full pl-12 pr-4 py-4 border-2 border-gray-200 rounded-xl focus:border-[#FFD900] focus:outline-none text-lg transition-colors"
                  autoFocus
                />
              </div>
              <div className="flex gap-3">
                <button
                  type="submit"
                  className="flex-1 bg-gradient-to-r from-[#1F5F9E] to-[#2976BA] text-white font-bold py-3 px-6 rounded-xl hover:shadow-lg transition-all transform hover:scale-105"
                >
                  {isVi ? 'Tìm kiếm' : 'Search'}
                </button>
                <button
                  type="button"
                  onClick={() => setIsSearchOpen(false)}
                  className="px-6 py-3 border-2 border-gray-300 text-gray-700 font-semibold rounded-xl hover:bg-gray-50 transition-colors"
                >
                  {isVi ? 'Hủy' : 'Cancel'}
                </button>
              </div>
              <div className="pt-4 border-t border-gray-200">
                <p className="text-sm text-gray-500 mb-3">
                  {isVi ? 'Tìm kiếm phổ biến:' : 'Popular searches:'}
                </p>
                <div className="flex flex-wrap gap-2">
                  {[
                    { vi: 'Vận chuyển', en: 'Transport' },
                    { vi: 'Cẩu máy', en: 'Lifting' },
                    { vi: 'Đóng gói', en: 'Packaging' },
                    { vi: 'Lắp đặt', en: 'Installation' },
                  ].map((item, index) => (
                    <button
                      key={index}
                      type="button"
                      onClick={() => setSearchTerm(isVi ? item.vi : item.en)}
                      className="px-4 py-2 bg-[#FFD900]/20 text-[#1F5F9E] rounded-full text-sm font-semibold hover:bg-[#FFD900] transition-colors"
                    >
                      {isVi ? item.vi : item.en}
                    </button>
                  ))}
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Main Layout with Background */}
      <div className="flex relative min-h-screen">
        {/* Left Sidebar Navigation */}
        <aside className="w-64 flex-shrink-0">
          <nav className="sticky top-0 space-y-2 p-2">
            {sidebarMenu.map((item, index) => {
              const isActive = item.href === `/${locale}/services`
              return (
                <Link
                  key={index}
                  href={item.href}
                  className={`block px-6 py-4 font-bold text-sm tracking-wide transition-all duration-300 relative rounded-l-xl ${
                    isActive 
                      ? 'bg-[#FFD900] text-[#1F5F9E] shadow-lg transform scale-105' 
                      : 'bg-[#1F5F9E] text-white hover:bg-[#2976BA] hover:transform hover:scale-105 hover:shadow-md'
                  }`}
                >
                  {item.title}
                  {isActive && (
                    <div 
                      className="absolute -right-3 top-1/2 -translate-y-1/2 w-0 h-0 animate-pulse"
                      style={{
                        borderTop: '12px solid transparent',
                        borderBottom: '12px solid transparent',
                        borderLeft: '12px solid #FFD900',
                      }}
                    />
                  )}
                </Link>
              )
            })}
          </nav>
        </aside>

        {/* Main Content - Large Padding with Transparent Background */}
        <main className="flex-1 p-8">
          <div className="max-w-6xl mx-auto">
            <div className="mb-8">
              <h1 className="text-3xl font-bold bg-gradient-to-r from-[#1F5F9E] to-[#FFD900] bg-clip-text text-transparent mb-8 leading-tight py-2">
                {isVi ? 'DỊCH VỤ CỦA CHÚNG TÔI' : 'OUR SERVICES'}
              </h1>
              
              {/* Not Found Message */}
              {notfound && search && (
                <div className="glass-card p-8 mb-8 border-l-4 border-[#FFD900]">
                  <div className="flex items-start gap-4">
                    <div className="flex-shrink-0">
                      <HiSearch className="w-8 h-8 text-[#1F5F9E]" />
                    </div>
                    <div className="flex-1">
                      <h3 className="text-xl font-bold text-[#1F5F9E] mb-2">
                        {isVi ? 'Không tìm thấy kết quả' : 'No Results Found'}
                      </h3>
                      <p className="text-gray-700 mb-4">
                        {isVi 
                          ? `Không tìm thấy dịch vụ phù hợp với từ khóa "${search}". Vui lòng xem tất cả dịch vụ của chúng tôi bên dưới hoặc thử tìm kiếm với từ khóa khác.`
                          : `No services found matching "${search}". Please browse all our services below or try searching with different keywords.`
                        }
                      </p>
                      <button
                        onClick={() => setIsSearchOpen(true)}
                        className="inline-flex items-center gap-2 bg-[#1F5F9E] text-white px-6 py-2 rounded-lg hover:bg-[#2976BA] transition-colors font-semibold"
                      >
                        <HiSearch className="w-4 h-4" />
                        {isVi ? 'Tìm kiếm lại' : 'Search Again'}
                      </button>
                    </div>
                  </div>
                </div>
              )}

              <p className="text-xl text-gray-800 mb-12">
                {isVi
                  ? 'Chúng tôi cung cấp các giải pháp logistics toàn diện với chất lượng tốt nhất và chi phí tối ưu.'
                  : 'We provide comprehensive logistics solutions with the best quality and optimal costs.'}
              </p>

              {/* Services Grid */}
              <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                {services.map((service, index) => (
                  <Link key={index} href={`/${locale}${service.link}`} className="glass-card overflow-hidden group cursor-pointer flex flex-col h-full">
                    <div className="relative h-48 overflow-hidden flex-shrink-0">
                      <Image
                        src={service.image}
                        alt={service.title}
                        fill
                        className="object-cover group-hover:scale-110 transition-transform duration-300"
                      />
                      <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                    </div>
                    <div className="p-6 bg-white/90 flex flex-col flex-grow">
                      <h3 className="text-xl font-bold text-[#1F5F9E] mb-3 leading-tight group-hover:text-[#FFD900] transition-colors">
                        {service.title}
                      </h3>
                      <p className="text-gray-700 text-sm leading-relaxed mb-4 flex-grow">{service.description}</p>
                      <span className="inline-flex items-center text-[#FFD900] font-semibold group-hover:gap-2 transition-all mt-auto">
                        {isVi ? 'Xem chi tiết' : 'View details'}
                        <span className="group-hover:translate-x-1 transition-transform">→</span>
                      </span>
                    </div>
                  </Link>
                ))}
              </div>
            </div>
          </div>
        </main>

        {/* Right Social Sidebar */}
        <aside className="w-16 flex-shrink-0">
          <div className="sticky top-0 flex flex-col gap-3 pt-2">
            <a
              href="#"
              className="w-12 h-12 bg-gray-600 hover:bg-[#1F5F9E] flex items-center justify-center text-white transition-colors mx-auto"
            >
              <FaYoutube className="w-5 h-5" />
            </a>
            <a
              href="#"
              className="w-12 h-12 bg-gray-600 hover:bg-[#1F5F9E] flex items-center justify-center text-white transition-colors mx-auto"
            >
              <FaLinkedin className="w-5 h-5" />
            </a>
            <a
              href="#"
              className="w-12 h-12 bg-gray-600 hover:bg-[#1F5F9E] flex items-center justify-center text-white transition-colors mx-auto"
            >
              <FaInstagram className="w-5 h-5" />
            </a>
            <a
              href="#"
              className="w-12 h-12 bg-gray-600 hover:bg-[#1F5F9E] flex items-center justify-center text-white transition-colors mx-auto"
            >
              <FaFacebook className="w-5 h-5" />
            </a>
          </div>
        </aside>
      </div>
      </div>
    </div>
  )
}
